import mysql.connector

def import_data_with_load_data_infile(db_config, table_name, file_path, fields_terminated_by=',', lines_terminated_by='\n', enclosed_by='"', optionally_enclosed=True, ignore_lines=1):
    """
    Imports data into a MySQL table using the LOAD DATA INFILE statement.

    Args:
        db_config (dict): A dictionary containing database connection details
                          (e.g., host, user, password, database).
        table_name (str): The name of the table to import data into.
        file_path (str): The full path to the data file on the client system.
                         MySQL server must have LOCAL INFILE enabled and the user
                         must have FILE privilege.
        fields_terminated_by (str): The character sequence that terminates fields.
                                    Default is ','.
        lines_terminated_by (str): The character sequence that terminates lines.
                                   Default is '\n'.
        enclosed_by (str): The character that encloses fields. Default is '"'.
        optionally_enclosed (bool): If True, fields are OPTIONALLY ENCLOSED.
                                    If False, fields are ENCLOSED. Default is True.
        ignore_lines (int): Number of lines to ignore at the beginning of the file.
                            Useful for CSV headers. Default is 1.
    """
    conn = None
    cursor = None
    try:
        # Establish connection with local_infile=True
        conn = mysql.connector.connect(
            host=db_config['host'],
            user=db_config['user'],
            password=db_config['password'],
            database=db_config['database'],
            local_infile=True  # Enable LOCAL INFILE for the connection
        )
        cursor = conn.cursor()

        # Construct the LOAD DATA INFILE statement
        enclosure_clause = f"OPTIONALLY ENCLOSED BY '{enclosed_by}'" if optionally_enclosed else f"ENCLOSED BY '{enclosed_by}'"
        
        load_data_sql = (
            f"LOAD DATA LOCAL INFILE '{file_path}' "
            f"INTO TABLE {table_name} "
            f"FIELDS TERMINATED BY '{fields_terminated_by}' "
            f"{enclosure_clause} "
            f"LINES TERMINATED BY '{lines_terminated_by}' "
            f"IGNORE {ignore_lines} LINES"
        )
        
        print(f"Executing: {load_data_sql}")
        cursor.execute(load_data_sql)
        conn.commit()

        print(f"Successfully imported {cursor.rowcount} rows into {table_name}.")

    except mysql.connector.Error as err:
        print(f"Error: {err}")
        if conn and conn.is_connected():
            conn.rollback()
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
    finally:
        if cursor:
            cursor.close()
        if conn and conn.is_connected():
            conn.close()
            print("MySQL connection closed.")

